// old code
fetch("assets\\content.json")
.then(response => response.json())
.then(data => {
    document.querySelector("#frp").innerText = data.fisnar_robot_plugin.description;
    document.querySelector("#stirbot").innerText = data.stirbot.description;
    document.querySelector("#rkt_case").innerText = data.rkt_case.description;
    document.querySelector("#gcodebuddy").innerText = data.gcodebuddy.description;
})

